import psutil

def kill_process_by_port(port):
    # 遍历所有运行的进程
    for proc in psutil.process_iter(['pid', 'name', 'ports']):
        try:
            # 检查进程是否使用了指定的端口
            if proc.info['ports']:
                for p in proc.info['ports']:
                    if p.laddr.port == port:
                        # 发现使用该端口的进程，杀死它
                        proc.kill()
                        print(f"Process {proc.info['pid']} using port {port} has been killed.")
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass

